using Microsoft.EntityFrameworkCore; using ModularMonolith.BuildingBlocks.Errors; using ModularMonolith.Modules.Orders.Domain; using ModularMonolith.Modules.Orders.Infrastructure; using ModularMonolith.Modules.Products.Contracts; using ModularMonolith.Modules.Users.Contracts; namespace ModularMonolith.Modules.Orders.Application;
public sealed class OrdersService(OrdersDbContext db,IUsersModule users,IProductsModule products){ public async Task<Result<CreateOrderResponse>> CreateAsync(Guid userId,IReadOnlyCollection<CreateOrderItem> requestItems,CancellationToken ct){ if(requestItems.Count==0)return Result<CreateOrderResponse>.Failure("orders.empty","Order must contain at least one item.",400); if(requestItems.Any(x=>x.Quantity<=0))return Result<CreateOrderResponse>.Failure("orders.invalid_quantity","Quantity must be positive.",400); var user=await users.GetUserForOrderAsync(userId,ct); if(user is null)return Result<CreateOrderResponse>.Failure("orders.user_missing","User was not found.",404); if(!user.IsActive)return Result<CreateOrderResponse>.Failure("orders.user_inactive","User is inactive.",409); var snapshots=new List<(Guid,string,decimal,int)>(); foreach(var item in requestItems){ var product=await products.GetProductForOrderAsync(item.ProductId,ct); if(product is null)return Result<CreateOrderResponse>.Failure("orders.product_missing","Product was not found.",404); if(!product.IsActive)return Result<CreateOrderResponse>.Failure("orders.product_inactive",$"Product {product.Name} is inactive.",409); if(product.AvailableStock<item.Quantity)return Result<CreateOrderResponse>.Failure("orders.insufficient_stock",$"Product {product.Name} does not have enough stock.",409); snapshots.Add((product.Id,product.Name,product.Price,item.Quantity)); } var order=Order.Create(userId,snapshots); foreach(var i in requestItems) await products.ReserveStockAsync(i.ProductId,i.Quantity,ct); db.Orders.Add(order); await db.SaveChangesAsync(ct); return Result<CreateOrderResponse>.Success(new(order.Id),201);} public async Task<Result<OrderResponse>> GetAsync(Guid id,CancellationToken ct){var o=await db.Orders.Include(x=>x.Items).SingleOrDefaultAsync(x=>x.Id==id,ct); return o is null?Result<OrderResponse>.Failure("orders.not_found","Order was not found.",404):Result<OrderResponse>.Success(Map(o));} public async Task<IReadOnlyCollection<OrderResponse>> ListAsync(CancellationToken ct)=>await db.Orders.Include(x=>x.Items).OrderByDescending(x=>x.CreatedAtUtc).Select(x=>Map(x)).ToListAsync(ct); static OrderResponse Map(Order o)=>new(o.Id,o.UserId,o.Total,o.CreatedAtUtc,o.Items.Select(i=>new OrderItemResponse(i.ProductId,i.ProductName,i.UnitPrice,i.Quantity,i.LineTotal)).ToList());}
public sealed record CreateOrderItem(Guid ProductId,int Quantity); public sealed record CreateOrderResponse(Guid OrderId); public sealed record OrderResponse(Guid Id,Guid UserId,decimal Total,DateTime CreatedAtUtc,IReadOnlyCollection<OrderItemResponse> Items); public sealed record OrderItemResponse(Guid ProductId,string ProductName,decimal UnitPrice,int Quantity,decimal LineTotal);
